package org.apache.camel.component.fix;

import java.util.Map;

import org.apache.camel.CamelContext;
import org.apache.camel.Endpoint;
import org.apache.camel.spi.Metadata;
import org.apache.camel.spi.annotations.Component;
import org.apache.camel.support.DefaultComponent;
import org.apache.camel.util.ObjectHelper;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * Camel component for FIX (Financial Information eXchange) protocol messaging
 */
@Component("fix")
public class FixComponent extends DefaultComponent {

    private static final Logger LOG = LoggerFactory.getLogger(FixComponent.class);

    @Metadata
    private FixConfiguration configuration = new FixConfiguration();

    public FixComponent() {
    }

    public FixComponent(CamelContext context) {
        super(context);
    }

    @Override
    protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
        if (ObjectHelper.isEmpty(remaining)) {
            throw new IllegalArgumentException("Session ID must be configured on endpoint using syntax fix:sessionID");
        }

        FixEndpoint endpoint = new FixEndpoint(uri, this);
        FixConfiguration copy = new FixConfiguration();
        copyProperties(configuration, copy);
        endpoint.setConfiguration(copy);

        setProperties(endpoint, parameters);

        // Set sessionID from the remaining part of the URI
        if (endpoint.getConfiguration().getSenderCompID() == null) {
            endpoint.getConfiguration().setSenderCompID(remaining);
        }

        return endpoint;
    }

    private void copyProperties(FixConfiguration source, FixConfiguration target) {
        target.setConfigFile(source.getConfigFile());
        target.setSenderCompID(source.getSenderCompID());
        target.setTargetCompID(source.getTargetCompID());
        target.setFixVersion(source.getFixVersion());
        target.setHeartBeatInterval(source.getHeartBeatInterval());
        target.setSocketConnectHost(source.getSocketConnectHost());
        target.setSocketConnectPort(source.getSocketConnectPort());
    }

    public FixConfiguration getConfiguration() {
        return configuration;
    }

    /**
     * Allows to pre-configure the FIX component with common options that the endpoints will reuse.
     */
    public void setConfiguration(FixConfiguration configuration) {
        this.configuration = configuration;
    }

    public String getConfigFile() {
        return configuration.getConfigFile();
    }

    /**
     * Configuration file for FIX settings
     */
    public void setConfigFile(String configFile) {
        configuration.setConfigFile(configFile);
    }

    public String getSenderCompID() {
        return configuration.getSenderCompID();
    }

    /**
     * The SenderCompID to identify yourself
     */
    public void setSenderCompID(String senderCompID) {
        configuration.setSenderCompID(senderCompID);
    }

    public String getTargetCompID() {
        return configuration.getTargetCompID();
    }

    /**
     * The TargetCompID to identify the target
     */
    public void setTargetCompID(String targetCompID) {
        configuration.setTargetCompID(targetCompID);
    }

    public String getFixVersion() {
        return configuration.getFixVersion();
    }

    /**
     * FIX protocol version (e.g., FIXT11, FIX44)
     */
    public void setFixVersion(String fixVersion) {
        configuration.setFixVersion(fixVersion);
    }

    public int getHeartBeatInterval() {
        return configuration.getHeartBeatInterval();
    }

    /**
     * Heartbeat interval in seconds
     */
    public void setHeartBeatInterval(int heartBeatInterval) {
        configuration.setHeartBeatInterval(heartBeatInterval);
    }

    public String getSocketConnectHost() {
        return configuration.getSocketConnectHost();
    }

    /**
     * Socket connection host for initiator sessions
     */
    public void setSocketConnectHost(String socketConnectHost) {
        configuration.setSocketConnectHost(socketConnectHost);
    }

    public int getSocketConnectPort() {
        return configuration.getSocketConnectPort();
    }

    /**
     * Socket connection port for initiator sessions
     */
    public void setSocketConnectPort(int socketConnectPort) {
        configuration.setSocketConnectPort(socketConnectPort);
    }
}

